import { describe, it, expect } from "vitest";
import { run } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Empty / simplest
  it("empty item list quote → premium 5 G (only processing fee)", () => {
    const result = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });

  // Base premiums for main items: base + 10% first-insurance + 5 fee
  it("quote single sword → 100 + 10 first-ins + 5 fee = 115 G", () => {
    const result = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("quote single amulet → 60 + 6 first-ins + 5 fee = 71 G", () => {
    const result = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("quote single staff → 80 + 8 first-ins + 5 fee = 93 G", () => {
    const result = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "staff" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 93 }] });
  });
  it("quote single potion → 40 + 4 first-ins + 5 fee = 49 G", () => {
    const result = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "potion" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 49 }] });
  });

  // Component base premiums
  it("quote single rune → 25 + 2.5 first-ins + 5 fee = 32.5 → 33 G", () => {
    const result = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 33 }] });
  });
  it("quote single moonstone → 25 + 2.5 first-ins + 5 fee = 32.5 → 33 G", () => {
    const result = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "moonstone" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 33 }] });
  });

  // Block of 3 alike components
  it("quote 2 runes → 50 + 5 first-ins + 5 fee = 60 G", () => {
    const result = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 60 }] });
  });
  it("quote 3 runes → 60 (block) + 6 first-ins + 5 fee = 71 G", () => {
    const result = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("quote 4 runes → 100 + 10 first-ins + 5 fee = 115 G (no block)", () => {
    const result = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("quote 7 runes → 175 + 17.5 first-ins + 5 fee = 197.5 → 198 G", () => {
    const result = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: Array.from({ length: 7 }, () => ({ type: "rune" })),
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 198 }] });
  });

  // Alike components — different types do not form a block together
  it("quote 2 runes + 1 moonstone → 75 + 7.5 first-ins + 5 fee = 87.5 → 88 G", () => {
    const result = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 88 }] });
  });
  it("quote 3 runes + 3 moonstones → 120 (two blocks) + 12 first-ins + 5 fee = 137 G", () => {
    const result = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "moonstone" },
            { type: "moonstone" },
            { type: "moonstone" },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 137 }] });
  });


  // High enchantment item-specific
  it("quote sword enchantment 5 → 100 + 30 high-enchant + 10 first-ins + 5 fee = 145 G (threshold)", () => {
    const result = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", enchantment: 5 }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 145 }] });
  });
  it.todo("quote sword enchantment 4 → 100 + 5 fee = 105 G (below threshold)");
  it.todo("quote cursed sword enchantment 5 → 100 + 50 + 30 + 5 = 185 G");

  // Policy-wide modifiers
  it.todo("quote cursed sword + plain amulet → 160 base + 50 curse + 5 fee = 215 G");
  it.todo("quote single sword with customer 2 years → 100 - 20 loyalty + 5 fee = 85 G (threshold)");
  it.todo("second quote in scenario gets follow-up contract discount → 100 + 10 first ins - 15 follow-up + 5 = 100 G");

  // Rounding in MHPCO's favor
  it.todo("premium calculation yielding 197.5 G → rounded up to 198 G");

  // Integration examples
  it("newcomer with cursed sword (steel, ench 3) → 165 G", () => {
    const result = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "sword", material: "steel", enchantment: 3, cursed: true },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 165 }] });
  });
  it.todo("long-standing customer's second contract: cursed sword ench 7 → 160 G");

  // Unknown item type
  it.todo("quote with unknown item type throws (CLI exits non-zero)");

  // Claims — standard reimbursement
  it.todo("claim regular sword damage 500 → payout 400 (full minus 100 deductible)");
  it.todo("claim rune damage 200 → payout 100 (full minus 100 deductible)");

  // Claims — enchantment >= 8 (50%)
  it.todo("claim steel sword ench 9 damage 1000 → payout 400 (50% then deductible)");

  // Claims — dragon material full
  it.todo("claim dragon sword ench 5 damage 800 → payout 700 (full then deductible)");

  // Claims — both clauses, 50% wins
  it.todo("claim dragon sword ench 9 damage 1000 → payout 400 (50% wins, then deductible)");
  it.todo("claim dragon sword ench 8 damage 1000 → payout 400 (high-ench threshold then deductible)");

  // Deductible per damaged item
  it.todo("dragon attack damaging sword 500 + amulet 300 → payout 600 (deductible per item)");

  // Multiple items same type
  it.todo("policy with two swords, two sword damages → both processed separately");
  it.todo("claim with more damages of a type than insured → throws");

  // Cap exhaustion
  it.todo("sword cap 2000; two claims 1500 each → first payout 1400 cap 600, second payout 600 cap 0");
  it.todo("cap based on unmodified insurance value (cursed sword cap 2000)");
  it.todo("sword + 3 runes insurance sum 1750 (block discount doesn't affect insurance sum)");

  // Claims — payout rounding (down in MHPCO's favor)
  it.todo("payout calculation yielding 350.5 G → rounded down to 350 G");

  // Claims — errors
  it.todo("claim for item not in policy throws");
  it.todo("claim with negative damage amount throws");
});

