  const { items } = step;
  const policyBase = policyBasePremium(items);
  const premium =
    policyBase +
    policyAdjustment({ customer, stepIndex }, policyBase) +
    totalItemSurcharges(items);
  return { premium: Math.ceil(premium) + PROCESSING_FEE };
};

const INSURANCE_VALUE: Record<string, number> = {
  sword: 1000,
  amulet: 600,
  staff: 800,
  potion: 400,
  rune: 250,
  moonstone: 250,
};
const DEDUCTIBLE = 100;
const CAP_MULTIPLIER = 2;

const insuranceSum = (items: Item[]) =>
  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);

const payoutForDamage = (damage: Damage) =>
  Math.max(0, damage.amount - DEDUCTIBLE);

type PolicyState = { items: Item[]; remainingCap: number };

const claim = (step: ClaimStep, policies: PolicyState[]) => {
  const policy = policies[step.policy];
  const payout = step.incident.damages.reduce(
    (sum, d) => sum + payoutForDamage(d),
    0,
  );
  policy.remainingCap -= payout;
  return { payout: Math.floor(payout), remainingCap: policy.remainingCap };
};

export const run = (input: Scenario): unknown => {
  const policies: PolicyState[] = [];
  const results = input.steps.map((step, i) => {
    if (step.op === "quote") {
      policies[i] = {
        items: step.items,
        remainingCap: insuranceSum(step.items) * CAP_MULTIPLIER,
      };
      return quote(step, input.customer, i);
    }
    return claim(step, policies);
  });
  return { results };
};

