const PROCESSING_FEE = 5;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

type Item = {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
};
type QuoteStep = { op: "quote"; items: Item[] };
type Damage = { itemType: string; amount: number };
type ClaimStep = {
  op: "claim";
  policy: number;
  incident: { cause: string; damages: Damage[] };
};
type Step = QuoteStep | ClaimStep;
type Customer = { yearsWithMHPCO: number };
type Scenario = { customer: Customer; steps: Step[] };

const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;
const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const CURSED_RATE = 0.5;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const HIGH_ENCHANTMENT_RATE = 0.3;

type Rule<T> = { applies: (subject: T) => boolean; rate: number };

const sumApplicableRates = <T>(rules: Rule<T>[], subject: T): number =>
  rules
    .filter((rule) => rule.applies(subject))
    .reduce((sum, rule) => sum + rule.rate, 0);

const isCursed = (item: Item): boolean => item.cursed === true;
const isHighlyEnchanted = (item: Item): boolean =>
  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;

const SURCHARGE_RULES: Rule<Item>[] = [
  { applies: isCursed, rate: CURSED_RATE },
  { applies: isHighlyEnchanted, rate: HIGH_ENCHANTMENT_RATE },
];

const groupByType = (items: Item[]): Map<string, Item[]> => {
  const groups = new Map<string, Item[]>();
  for (const item of items) {
    const group = groups.get(item.type) ?? [];
    group.push(item);
    groups.set(item.type, group);
  }
  return groups;
};

const basePremiumFor = (type: string) => {
  const base = BASE_PREMIUM[type];
  if (base === undefined) throw new Error(`Unknown item type: ${type}`);
  return base;
};

const premiumForGroup = (type: string, group: Item[]) => {
  if (COMPONENT_TYPES.has(type) && group.length === BLOCK_SIZE) {
    return BLOCK_PREMIUM;
  }
  return group.length * basePremiumFor(type);
};

const surchargeForItem = (item: Item) =>
  basePremiumFor(item.type) * sumApplicableRates(SURCHARGE_RULES, item);

const policyBasePremium = (items: Item[]) =>
  [...groupByType(items)].reduce(
    (total, [type, group]) => total + premiumForGroup(type, group),
    0,
  );

const totalItemSurcharges = (items: Item[]) =>
  items.reduce((sum, item) => sum + surchargeForItem(item), 0);

const FIRST_INSURANCE_RATE = 0.1;
const LOYALTY_THRESHOLD_YEARS = 2;
const LOYALTY_RATE = 0.2;
const FOLLOWUP_RATE = 0.15;

type QuoteContext = { customer: Customer; stepIndex: number };

const POLICY_ADJUSTMENTS: Rule<QuoteContext>[] = [
  { applies: () => true, rate: FIRST_INSURANCE_RATE },
  {
    applies: ({ customer }) => customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS,
    rate: -LOYALTY_RATE,
  },
  { applies: ({ stepIndex }) => stepIndex > 0, rate: -FOLLOWUP_RATE },
];

const policyAdjustment = (ctx: QuoteContext, policyBase: number) =>
  policyBase * sumApplicableRates(POLICY_ADJUSTMENTS, ctx);

const quote = (step: QuoteStep, customer: Customer, stepIndex: number) => {
  const { items } = step;
  const policyBase = policyBasePremium(items);
  const premium =
    policyBase +
    policyAdjustment({ customer, stepIndex }, policyBase) +
    totalItemSurcharges(items);
  return { premium: Math.ceil(premium) + PROCESSING_FEE };
};

export const run = (input: Scenario): unknown => ({
  results: input.steps.map((step, i) => quote(step, input.customer, i)),
});

