it("claim rune damage 200 → payout 100 (full minus 100 deductible)", () => {
  const result = run({
    customer: { yearsWithMHPCO: 0 },
    steps: [
      { op: "quote", items: [{ type: "rune" }] },
      {
        op: "claim",
        policy: 0,
        incident: {
          cause: "explosion",
          damages: [{ itemType: "rune", amount: 200 }],
        },
      },
    ],
  });
  expect(result).toEqual({
    results: [
      { premium: 33 },
      { payout: 100, remainingCap: 400 },
    ],
  });
});

